import{_ as a,o as i,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"5. Higher Duties","description":"","frontmatter":{"title":"5. Higher Duties","eba":"Health Allied & Managers Admin 2021-2025","topics":["preliminary","classifications","wages","higher-duties"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/allowances/5-higher-duties.md","filePath":"ebas/has-managers-admin/managers-admin/allowances/5-higher-duties.md"}'),s={name:"ebas/has-managers-admin/managers-admin/allowances/5-higher-duties.md"};function n(o,e,h,d,l,g){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_5-higher-duties" tabindex="-1">5. Higher Duties <a class="header-anchor" href="#_5-higher-duties" aria-label="Permalink to &quot;5. Higher Duties&quot;">​</a></h1><p><strong>5.1</strong> Employees, who are engaged in duties that carry a higher rate of pay than the Employee’s ordinary classification, will be entitled to payment of higher duties in accordance with the provisions of this clause.</p><p><strong>5.2</strong> Employees who are required to assume the duties of an Employee on a higher classification for a period of five consecutive working days or more will be paid not less than the minimum rate for the classification of the Employee being relieved, for the period of higher duties.</p><p><strong>5.3</strong> Administrative Worker 1A Instead of the entitlement under subclause 5.1 above, Employees engaged in the classification of Grade 1A (under either Part 1 or Part 2 of <a href="/eba/ebas/has-managers-admin/schedules/3d-classification-structure-managers-and-administrative-workers.html">Schedule 3D</a>) who are engaged for more than one hour in duties carrying a higher rate than their ordinary classification, will be paid the higher rate of pay for the full day or shift. If such Employee is engaged in higher duties for one hour or less, they are only entitled to payment at the higher rate for the time actually worked.</p><p>Plain language terms: acting up, higher duties allowance, HDA.</p>',5)])])}const u=a(s,[["render",n]]);export{m as __pageData,u as default};
